import{_ as e}from"./chunks/09-auditor-md-excerpt.Uu8bSm6-.js";import{_ as r,o as a,c as o,a2 as s}from"./chunks/framework.DTa47_fH.js";const m=JSON.parse('{"title":"Generate Report","description":"","frontmatter":{},"headers":[],"relativePath":"generate-report.md","filePath":"generate-report.md"}'),n={name:"generate-report.md"};function i(d,t,p,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="generate-report" tabindex="-1">Generate Report <a class="header-anchor" href="#generate-report" aria-label="Permalink to &quot;Generate Report&quot;">​</a></h1><p>Generate Report produces text and Markdown reports from the latest assessment results. Reports give you a portable, readable version of the findings that can be shared with reviewers who do not have SWAO or Power BI installed.</p><p>Access from the TUI main menu by pressing <strong>4</strong>, or from the command line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao report --app &lt;app-id&gt;</span></span></code></pre></div><hr><h2 id="sample-output" tabindex="-1">Sample output <a class="header-anchor" href="#sample-output" aria-label="Permalink to &quot;Sample output&quot;">​</a></h2><p>The auditor report is a structured Markdown document you can open in any editor, attach to an email, or render directly in GitHub or Confluence.</p><p><img src="'+e+'" alt="Auditor report excerpt"></p><hr><h2 id="report-formats" tabindex="-1">Report formats <a class="header-anchor" href="#report-formats" aria-label="Permalink to &quot;Report formats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>File</th><th>Best for</th></tr></thead><tbody><tr><td><strong>Markdown auditor report</strong></td><td><code>apps/&lt;id&gt;/wsp/auditor.md</code></td><td>Compliance reviewers who prefer text; printing; email attachment</td></tr><tr><td><strong>YAML signal pack</strong></td><td><code>apps/&lt;id&gt;/wsp/signals/*.yaml</code></td><td>Downstream tooling; import into other systems</td></tr><tr><td><strong>JSON summary</strong></td><td><code>apps/&lt;id&gt;/wsp/summary.json</code></td><td>API consumers; custom dashboards</td></tr><tr><td><strong>PDF</strong></td><td><code>apps/&lt;id&gt;/wsp/reports/&lt;id&gt;.pdf</code></td><td>Formal submission; requires Playwright</td></tr></tbody></table><hr><h2 id="auditor-report-contents" tabindex="-1">Auditor report contents <a class="header-anchor" href="#auditor-report-contents" aria-label="Permalink to &quot;Auditor report contents&quot;">​</a></h2><p>The Markdown auditor report (<code>auditor.md</code>) is the human-readable version of the full assessment. It contains:</p><ul><li><strong>Summary block</strong> -- workload identity, 7R migration verdict, coverage score, active frameworks, signal outcome counts.</li><li><strong>Compliance status by framework</strong> -- every control with its verdict (SATISFIED / GAP / PARTIAL / NOT ASSESSED) and the rationale text that produced it.</li><li><strong>Risk register</strong> -- derived risks with likelihood, impact, trigger, and mitigation.</li><li><strong>Per-signal drill-down</strong> -- every signal with ID, severity, evidence reference, and the <code>false_positive_considered</code> flag.</li><li><strong>Run statistics</strong> -- which passes ran, how many signals each produced, wall-clock time, and LLM token usage.</li></ul><hr><h2 id="pdf-generation" tabindex="-1">PDF generation <a class="header-anchor" href="#pdf-generation" aria-label="Permalink to &quot;PDF generation&quot;">​</a></h2><p>PDF output requires Playwright to be installed (see Health Check probe 2). If Playwright is present, SWAO renders the HTML publication to PDF automatically when you add the <code>--format pdf</code> flag:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao report --app &lt;app-id&gt; --format pdf</span></span></code></pre></div><p>The PDF is a faithful rendering of the HTML publication, including all charts and tables, in a format suitable for formal submission to a regulatory body or external auditor.</p><hr><h2 id="regenerating-reports" tabindex="-1">Regenerating reports <a class="header-anchor" href="#regenerating-reports" aria-label="Permalink to &quot;Regenerating reports&quot;">​</a></h2><p>Reports are always generated from the stored signal set -- they do not require a new assessment run. If you update a context document or change the active frameworks and want to see the impact, run the assessment again first, then regenerate reports.</p>',23)])])}const f=r(n,[["render",i]]);export{m as __pageData,f as default};
